using WAYN.Games.MGM.Locomotion.Runtime.Systems;
using Unity.Burst;
using Unity.Collections;
using Unity.Entities;
using Unity.Physics;
using Unity.Physics.Systems;

namespace #NAME_SPACE#.Systems
{
 /// <summary>
 /// ECS system that schedules the locomotion job for all #StateMachineName# locomotor entities each fixed update.
 /// </summary>
 [UpdateInGroup(typeof(PhysicsSolveAndIntegrateGroup), OrderLast = true)]
 [BurstCompile]
 public partial struct #SYSTEM# : I#StateMachineName#LocomotionSystem
 {
 /// <summary>Cached job data bag updated each frame before scheduling the locomotion job.</summary>
 public I#StateMachineName#LocomotionSystem.LocomotionJobData JobData { get; set; }

 /// <summary>Entity query matching all locomotor entities with the required components.</summary>
 public EntityQuery LocomotorQuery { get; set; }

 /// <summary>Initialises the locomotor query and job data.</summary>
 public void OnCreate(ref SystemState state)
 {
 state.RequireForUpdate<PhysicsWorldSingleton>();
 LocomotorQuery = I#StateMachineName#LocomotionSystem
 .LocomotorQueryBuilder(Allocator.Temp)
 .Build(ref state);

 JobData = new I#StateMachineName#LocomotionSystem.LocomotionJobData(ref state);
 }

 /// <summary>Updates job data and schedules the parallel locomotion job for all matching entities.</summary>
 [BurstCompile]
 public void OnUpdate(ref SystemState state)
 {
 if (LocomotorQuery.IsEmptyIgnoreFilter) return;
 JobData = JobData.Update(ref state);

 state.Dependency = I#StateMachineName#LocomotionSystem
 .ScheduleParallelLocomotionJob(state.Dependency, SystemAPI.Time.DeltaTime, JobData, LocomotorQuery, SystemAPI.GetSingleton<PhysicsWorldSingleton>());
 }

 /// <summary>Cleans up resources.</summary>
 public void OnDestroy(ref SystemState state)
 {
 }
 }
